1	using System.Diagnostics.CodeAnalysis;
2	using Microsoft.CodeAnalysis;
3	using Riok.Mapperly.Abstractions;
4	using Riok.Mapperly.Descriptors.Constructors;
5	using Riok.Mapperly.Descriptors.MappingBodyBuilders.BuilderContext;
6	using Riok.Mapperly.Descriptors.Mappings;
7	using Riok.Mapperly.Descriptors.Mappings.MemberMappings;
8	using Riok.Mapperly.Diagnostics;
9	using Riok.Mapperly.Symbols.Members;
10	
11	namespace Riok.Mapperly.Descriptors.MappingBodyBuilders;
12	
13	/// <summary>
14	/// Body builder for new instance object member mappings (mappings for which the target object gets created via <code>new()</code>).
15	/// </summary>
16	public static class NewInstanceObjectMemberMappingBodyBuilder
17	{
18	    public static void BuildMappingBody(MappingBuilderContext ctx, NewInstanceObjectMemberMapping mapping)
19	    {
20	        var mappingCtx = new NewInstanceBuilderContext<NewInstanceObjectMemberMapping>(ctx, mapping);
21	        BuildConstructorMapping(mappingCtx);
22	        BuildInitMemberMappings(mappingCtx, true);
23	        mappingCtx.AddDiagnostics(true);
24	    }
25	
26	    public static void BuildMappingBody(MappingBuilderContext ctx, NewInstanceObjectMemberMethodMapping mapping)
27	    {
28	        var mappingCtx = new NewInstanceContainerBuilderContext<NewInstanceObjectMemberMethodMapping>(ctx, mapping);
29	        BuildConstructorMapping(mappingCtx);
30	        BuildInitMemberMappings(mappingCtx);
31	        ObjectMemberMappingBodyBuilder.BuildMappingBody(mappingCtx);
32	        mappingCtx.AddDiagnostics(true);
33	    }
34	
35	    public static IReadOnlyList<ConstructorParameterMapping> BuildConstructorMapping(
36	        INewInstanceBuilderContext<INewInstanceObjectMemberMapping> ctx,
37	        bool? preferParameterlessConstructor = null
38	    )
39	    {
40	        if (ctx.Mapping.HasConstructor)
41	            return [];
42	
43	        if (ctx.Mapping.TargetType is not INamedTypeSymbol namedTargetType)
44	        {
45	            ctx.BuilderContext.ReportDiagnostic(DiagnosticDescriptors.NoConstructorFound, ctx.BuilderContext.Target);
46	            return [];
47	        }
48	
49	        // attributed ctor is prio 1
50	        // if preferParameterlessConstructors is true (default) :parameterless ctor is prio 2 then by descending parameter count
51	        // the reverse if preferParameterlessConstructors is false , descending parameter count is prio2 then parameterless ctor
52	        // ctors annotated with [Obsolete] are considered last unless they have a MapperConstructor attribute set
53	        var ctorCandidates = namedTargetType
54	            .InstanceConstructors.Where(ctor => ctx.BuilderContext.SymbolAccessor.IsConstructorAccessible(ctor))
55	            .OrderByDescending(x => ctx.BuilderContext.SymbolAccessor.HasAttribute<MapperConstructorAttribute>(x))
56	            .ThenBy(x => ctx.BuilderContext.SymbolAccessor.HasAttribute<ObsoleteAttribute>(x));
57	
58	        if (preferParameterlessConstructor ?? ctx.BuilderContext.Configuration.Mapper.PreferParameterlessConstructors)
59	        {
60	            ctorCandidates = ctorCandidates.ThenByDescending(x => x.Parameters.Length == 0).ThenByDescending(x => x.Parameters.Length);
61	        }
62	        else
63	        {
64	            ctorCandidates = ctorCandidates.ThenByDescending(x => x.Parameters.Length).ThenByDescending(x => x.Parameters.Length == 0);
65	        }
66	
67	        foreach (var ctorCandidate in ctorCandidates)
68	        {
69	            if (!TryBuildConstructorMapping(ctx, ctorCandidate, out var constructorParameterMappings))
70	            {
71	                if (ctx.BuilderContext.SymbolAccessor.HasAttribute<MapperConstructorAttribute>(ctorCandidate))
72	                {
73	                    ctx.BuilderContext.ReportDiagnostic(
74	                        DiagnosticDescriptors.CannotMapToConfiguredConstructor,
75	                        ctx.Mapping.SourceType,
76	                        ctorCandidate
77	                    );
78	                }
79	
80	                continue;
81	            }
82	
83	            ctx.Mapping.Constructor = ctx.BuilderContext.InstanceConstructors.BuildForConstructor(ctorCandidate);
84	
85	            foreach (var mapping in constructorParameterMappings)
86	            {
87	                ctx.AddConstructorParameterMapping(mapping);
88	            }
89	
90	            return constructorParameterMappings;
91	        }
92	
93	        ctx.BuilderContext.ReportDiagnostic(DiagnosticDescriptors.NoConstructorFound, ctx.BuilderContext.Target);
94	        ctx.Mapping.Constructor = new InstanceConstructor(namedTargetType);
95	        return [];
96	    }
97	
98	    public static void BuildInitMemberMappings(
99	        INewInstanceBuilderContext<INewInstanceObjectMemberMapping> ctx,
100	        bool includeAllMembers = false
101	    )
102	    {
103	        if (!ctx.Mapping.Constructor.SupportsObjectInitializer)
104	            return;
105	
106	        var initOnlyTargetMembers = includeAllMembers
107	            ? ctx.EnumerateUnmappedTargetMembers().ToArray()
108	            : ctx.EnumerateUnmappedTargetMembers().Where(x => x.CanOnlySetViaInitializer()).ToArray();
109	        foreach (var targetMember in initOnlyTargetMembers)
110	        {
111	            if (ctx.TryMatchInitOnlyMember(targetMember, out var memberInfo))
112	            {
113	                BuildInitMemberMapping(ctx, memberInfo);
114	                continue;
115	            }
116	
117	            // set the member mapped as it is an init only member
118	            // diagnostics are already reported
119	            // and no further mapping attempts should be undertaken
120	            if (
121	                targetMember.IsRequired
122	                || ctx.BuilderContext.Configuration.HasRequiredMappingStrategyForMembers(RequiredMappingStrategy.Target)
123	            )
124	            {
125	                ctx.BuilderContext.ReportDiagnostic(
126	                    targetMember.IsRequired ? DiagnosticDescriptors.RequiredMemberNotMapped : DiagnosticDescriptors.SourceMemberNotFound,
127	                    targetMember.Name,
128	                    ctx.Mapping.TargetType,
129	                    ctx.Mapping.SourceType
130	                );
131	            }
132	            ctx.SetTargetMemberMapped(targetMember);
133	        }
134	    }
135	
136	    private static void BuildInitMemberMapping(
137	        INewInstanceBuilderContext<INewInstanceObjectMemberMapping> ctx,
138	        MemberMappingInfo memberInfo
139	    )
140	    {
141	        // consume member configs
142	        // to ensure no further mappings are created for these configurations,
143	        // even if a mapping validation fails
144	        ctx.ConsumeMemberConfigs(memberInfo);
145	
146	        if (!ObjectMemberMappingBodyBuilder.ValidateMappingSpecification(ctx, memberInfo, true))
147	            return;
148	
149	        if (!MemberMappingBuilder.TryBuildAssignment(ctx, memberInfo, out var memberAssignmentMapping))
150	            return;
151	
152	        ctx.AddInitMemberMapping(memberAssignmentMapping);
153	    }
154	
155	    private static bool TryBuildConstructorMapping(
156	        INewInstanceBuilderContext<IMapping> ctx,
157	        IMethodSymbol ctor,
158	        [NotNullWhen(true)] out List<ConstructorParameterMapping>? constructorParameterMappings
159	    )
160	    {
161	        constructorParameterMappings = [];
162	
163	        var skippedOptionalParam = false;
164	        foreach (var parameter in ctor.Parameters)
165	        {
166	            if (
167	                !ctx.TryMatchParameter(parameter, out var memberMappingInfo)
168	                || !SourceValueBuilder.TryBuildMappedSourceValue(ctx, memberMappingInfo, out var sourceValue)
169	            )
170	            {
171	                // expressions do not allow skipping of optional parameters
172	                if (!parameter.IsOptional || ctx.BuilderContext.IsExpression)
173	                    return false;
174	
175	                skippedOptionalParam = true;
176	                continue;
177	            }
178	
179	            var ctorMapping = new ConstructorParameterMapping(parameter, sourceValue, skippedOptionalParam, memberMappingInfo);
180	            constructorParameterMappings.Add(ctorMapping);
181	        }
182	
183	        return true;
184	    }
185	}
