1	using System.Diagnostics;
2	using System.Diagnostics.CodeAnalysis;
3	using Microsoft.CodeAnalysis;
4	using Riok.Mapperly.Descriptors.ObjectFactories;
5	using Riok.Mapperly.Descriptors.UnsafeAccess;
6	
7	namespace Riok.Mapperly.Descriptors.Constructors;
8	
9	public class InstanceConstructorFactory(
10	    ObjectFactoryCollection objectFactories,
11	    SymbolAccessor symbolAccessor,
12	    UnsafeAccessorContext unsafeAccessorContext
13	)
14	{
15	    /// <summary>
16	    /// Tries to build an <see cref="IInstanceConstructor"/>.
17	    /// Creates an object factory ctor if possible,
18	    /// tries to use an accessible parameterless ctor otherwise.
19	    /// </summary>
20	    public bool TryBuild(ITypeSymbol source, ITypeSymbol target, [NotNullWhen(true)] out IInstanceConstructor? constructor)
21	    {
22	        return TryBuildObjectFactory(source, target, out constructor) || TryBuildParameterless(target, out constructor);
23	    }
24	
25	    /// <summary>
26	    /// Tries to build an object factory constructor.
27	    /// </summary>
28	    public bool TryBuildObjectFactory(ITypeSymbol source, ITypeSymbol target, [NotNullWhen(true)] out IInstanceConstructor? constructor)
29	    {
30	        if (objectFactories.TryFindObjectFactory(source, target, out var factory))
31	        {
32	            constructor = new ObjectFactoryConstructorAdapter(factory, source, target);
33	            return true;
34	        }
35	
36	        constructor = null;
37	        return false;
38	    }
39	
40	    /// <summary>
41	    /// Tries to build a parameterless constructor.
42	    /// </summary>
43	    public bool TryBuildParameterless(ITypeSymbol type, [NotNullWhen(true)] out IInstanceConstructor? ctor)
44	    {
45	        if (type is not INamedTypeSymbol namedType || namedType.IsAbstract)
46	        {
47	            ctor = null;
48	            return false;
49	        }
50	
51	        var ctorMethod = namedType.InstanceConstructors.FirstOrDefault(x =>
52	            x.Parameters.IsDefaultOrEmpty && symbolAccessor.IsConstructorAccessible(x)
53	        );
54	        if (ctorMethod == null)
55	        {
56	            ctor = null;
57	            return false;
58	        }
59	
60	        ctor = BuildForConstructor(ctorMethod);
61	        return true;
62	    }
