1	using System.Diagnostics.CodeAnalysis;
2	using Microsoft.CodeAnalysis;
3	using Riok.Mapperly.Abstractions;
4	using Riok.Mapperly.Configuration.MethodReferences;
5	using Riok.Mapperly.Descriptors;
6	using Riok.Mapperly.Descriptors.Mappings;
7	using Riok.Mapperly.Descriptors.Mappings.UserMappings;
8	using Riok.Mapperly.Diagnostics;
9	using Riok.Mapperly.Helpers;
10	
11	namespace Riok.Mapperly.Configuration;
12	
13	public class MapperConfigurationReader
14	{
15	    private readonly Dictionary<MappingConfigurationReference, MappingConfiguration> _resolvedConfigurations = new();
16	    private readonly AttributeDataAccessor _dataAccessor;
17	    private readonly MappingCollection _mappings;
18	    private readonly GenericTypeChecker _genericTypeChecker;
19	    private readonly DiagnosticCollection _diagnostics;
20	    private readonly WellKnownTypes _types;
21	
22	    public MapperConfigurationReader(
23	        AttributeDataAccessor dataAccessor,
24	        MappingCollection mappings,
25	        GenericTypeChecker genericTypeChecker,
26	        DiagnosticCollection diagnostics,
27	        WellKnownTypes types,
28	        ISymbol mapperSymbol,
29	        MapperConfiguration defaultMapperConfiguration,
30	        SupportedFeatures supportedFeatures
31	    )
32	    {
33	        _dataAccessor = dataAccessor;
34	        _mappings = mappings;
35	        _genericTypeChecker = genericTypeChecker;
36	        _diagnostics = diagnostics;
37	        _types = types;
38	
39	        var mapperConfiguration = _dataAccessor.AccessSingle<MapperAttribute, MapperConfiguration>(mapperSymbol);
40	        var mapper = MapperConfigurationMerger.MergeToAttribute(mapperConfiguration, defaultMapperConfiguration);
41	
42	        MapperConfiguration = new MappingConfiguration(
43	            mapper,
44	            new EnumMappingConfiguration(
45	                mapper.EnumMappingStrategy,
46	                mapper.EnumMappingIgnoreCase,
47	                null,
48	                [],
49	                [],
50	                [],
51	                mapper.RequiredEnumMappingStrategy,
52	                mapper.EnumNamingStrategy
53	            ),
54	            new MembersMappingConfiguration([], [], [], [], [], mapper.IgnoreObsoleteMembersStrategy, mapper.RequiredMappingStrategy),
55	            [],
56	            mapper.UseDeepCloning,
57	            mapper.StackCloningStrategy,
58	            supportedFeatures
59	        );
60	    }
61	
62	    public MappingConfiguration MapperConfiguration { get; }
63	
64	    public MappingConfiguration BuildFor(MappingConfigurationReference reference, bool supportsDeepCloning)
65	    {
66	        if (_resolvedConfigurations.TryGetValue(reference, out var resolved))
67	        {
68	            return resolved;
69	        }
70	
71	        return BuildWithIncludedMappings([], reference, supportsDeepCloning);
72	    }
73	
74	    private MappingConfiguration BuildWithIncludedMappings(
75	        HashSet<IMethodSymbol> visitedMethods,
76	        MappingConfigurationReference reference,
77	        bool supportsDeepCloning
78	    )
79	    {
80	        if (reference.Method == null)
81	            return supportsDeepCloning ? MapperConfiguration : MapperConfiguration with { UseDeepCloning = false };
82	
83	        var enumConfig = BuildEnumConfig(reference);
84	        var membersConfig = BuildMembersConfig(reference);
85	        var derivedTypesConfig = BuildDerivedTypeConfigs(reference.Method);
86	        var configuration = new MappingConfiguration(
87	            MapperConfiguration.Mapper,
88	            enumConfig,
89	            membersConfig,
90	            derivedTypesConfig,
91	            supportsDeepCloning && MapperConfiguration.Mapper.UseDeepCloning,
92	            MapperConfiguration.StackCloningStrategy,
93	            MapperConfiguration.SupportedFeatures
94	        );
95	
96	        configuration = IncludeConfigurations(configuration, visitedMethods, reference, supportsDeepCloning);
97	        _resolvedConfigurations[reference] = configuration;
98	        return configuration;
99	    }
100	
101	    private MappingConfiguration IncludeConfigurations(
102	        MappingConfiguration configuration,
103	        HashSet<IMethodSymbol> visitedMethods,
104	        MappingConfigurationReference reference,
105	        bool supportsDeepCloning
106	    )
107	    {
108	        var includedMappingConfigs = _dataAccessor.Access<IncludeMappingConfigurationAttribute, IncludeMappingConfiguration>(
109	            reference.Method!
110	        );
111	        foreach (var includedCfg in includedMappingConfigs)
112	        {
113	            var cfgToInclude = BuildConfigToInclude(includedCfg.Name, reference, visitedMethods, supportsDeepCloning);
114	            if (cfgToInclude == null)
115	            {
116	                continue;
117	            }
118	
119	            configuration = configuration.Include(cfgToInclude);
120	        }
121	
122	        return configuration;
123	    }
124	
125	    private MappingConfiguration? BuildConfigToInclude(
126	        IMethodReferenceConfiguration name,
127	        MappingConfigurationReference configRef,
128	        HashSet<IMethodSymbol> visitedMethods,
129	        bool supportsDeepCloning
130	    )
131	    {
132	        var typeMapping =
133	            (ITypeMapping?)_mappings.FindNamedNewInstanceMapping(name.FullName, out var ambiguousName)
134	            ?? _mappings.FindExistingInstanceNamedMapping(name.FullName, out ambiguousName);
135	        var methodSymbol = (typeMapping as IUserMapping)?.Method;
136	        if (!ValidateIncludedConfig(ambiguousName, configRef, name.FullName, typeMapping, methodSymbol))
137	        {
138	            return null;
139	        }
140	
141	        if (!visitedMethods.Add(methodSymbol))
142	        {
143	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.CircularReferencedMapping, methodSymbol, methodSymbol.ToDisplayString());
144	            return null;
145	        }
146	
147	        var includedReference = new MappingConfigurationReference(methodSymbol, typeMapping.SourceType, typeMapping.TargetType);
148	        if (!_resolvedConfigurations.TryGetValue(includedReference, out var config))
149	        {
150	            config = BuildWithIncludedMappings(visitedMethods, includedReference, supportsDeepCloning);
151	        }
152	
153	        return config;
154	    }
155	
156	    private bool ValidateIncludedConfig(
157	        bool ambiguousName,
158	        MappingConfigurationReference configRef,
159	        string mappingToIncludeName,
160	        [NotNullWhen(true)] ITypeMapping? mappingToInclude,
161	        [NotNullWhen(true)] IMethodSymbol? mappingToIncludeMethodSymbol
162	    )
163	    {
164	        if (ambiguousName)
165	        {
166	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.ReferencedMappingAmbiguous, configRef.Method, mappingToIncludeName);
167	            return false;
168	        }
169	
170	        if (mappingToInclude is null || mappingToIncludeMethodSymbol is null)
171	        {
172	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.ReferencedMappingNotFound, configRef.Method, mappingToIncludeName);
173	            return false;
174	        }
175	
176	        var typeCheckerResult = _genericTypeChecker.InferAndCheckTypes(
177	            configRef.Method!.TypeParameters,
178	            (mappingToInclude.SourceType, configRef.Source),
179	            (mappingToInclude.TargetType, configRef.Target)
180	        );
181	
182	        if (typeCheckerResult.Success)
183	            return true;
184	
185	        if (ReferenceEquals(configRef.Source, typeCheckerResult.FailedArgument))
186	        {
187	            _diagnostics.ReportDiagnostic(
188	                DiagnosticDescriptors.SourceTypeIsNotAssignableToTheIncludedSourceType,
189	                configRef.Method,
190	                configRef.Source,
191	                mappingToInclude.SourceType
192	            );
193	        }
194	        else
195	        {
196	            _diagnostics.ReportDiagnostic(
197	                DiagnosticDescriptors.TargetTypeIsNotAssignableToTheIncludedTargetType,
198	                configRef.Method,
199	                configRef.Target,
200	                mappingToInclude.TargetType
201	            );
202	        }
203	
204	        return false;
205	    }
206	
207	    private IReadOnlyCollection<DerivedTypeMappingConfiguration> BuildDerivedTypeConfigs(IMethodSymbol method)
208	    {
209	        return _dataAccessor
210	            .Access<MapDerivedTypeAttribute, DerivedTypeMappingConfiguration>(method)
211	            .Concat(_dataAccessor.Access<MapDerivedTypeAttribute<object, object>, DerivedTypeMappingConfiguration>(method))
212	            .ToList();
213	    }
214	
215	    private MembersMappingConfiguration BuildMembersConfig(MappingConfigurationReference configRef)
216	    {
217	        if (configRef.Method == null)
218	            return MapperConfiguration.Members;
219	
220	        var ignoredSourceMembers = _dataAccessor
221	            .Access<MapperIgnoreSourceAttribute>(configRef.Method)
222	            .Select(x => x.Source)
223	            .WhereNotNull()
224	            .ToList();
225	        var ignoredTargetMembers = _dataAccessor
226	            .Access<MapperIgnoreTargetAttribute>(configRef.Method)
227	            .Select(x => x.Target)
228	            .WhereNotNull()
229	            .ToList();
230	        var memberValueConfigurations = _dataAccessor.Access<MapValueAttribute, MemberValueMappingConfiguration>(configRef.Method).ToList();
231	        var memberConfigurations = _dataAccessor
232	            .Access<MapPropertyAttribute, MemberMappingConfiguration>(configRef.Method)
233	            .Concat(_dataAccessor.Access<MapPropertyFromSourceAttribute, MemberMappingConfiguration>(configRef.Method))
234	            .ToList();
235	        var nestedMembersConfigurations = _dataAccessor
236	            .Access<MapNestedPropertiesAttribute, NestedMembersMappingConfiguration>(configRef.Method)
237	            .ToList();
238	        var ignoreObsolete = _dataAccessor
239	            .AccessFirstOrDefault<MapperIgnoreObsoleteMembersAttribute>(configRef.Method)
240	            ?.IgnoreObsoleteStrategy;
241	        var requiredMapping = _dataAccessor.AccessFirstOrDefault<MapperRequiredMappingAttribute>(configRef.Method)?.RequiredMappingStrategy;
242	
243	        // ignore the required mapping / ignore obsolete as the same attribute is used for other mapping types
244	        // e.g. enum to enum
245	        var hasMemberConfigs = ignoredSourceMembers.Count > 0 || ignoredTargetMembers.Count > 0 || memberConfigurations.Count > 0;
246	        if (hasMemberConfigs && (configRef.Source.IsEnum() || configRef.Target.IsEnum()))
247	        {
248	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.MemberConfigurationOnNonMemberMapping, configRef.Method);
249	            return MapperConfiguration.Members;
250	        }
251	
252	        if (
253	            hasMemberConfigs
254	            && configRef.Source.ImplementsGeneric(_types.Get(typeof(IQueryable<>)), out _)
255	            && configRef.Target.ImplementsGeneric(_types.Get(typeof(IQueryable<>)), out _)
256	        )
257	        {
258	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.MemberConfigurationOnQueryableProjectionMapping, configRef.Method);
259	            return MapperConfiguration.Members;
260	        }
261	
262	        foreach (var invalidMemberConfig in memberValueConfigurations.Where(x => !x.IsValid))
263	        {
264	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.InvalidMapValueAttributeUsage, invalidMemberConfig.Location);
265	        }
266	
267	        foreach (var invalidMemberConfig in memberConfigurations.Where(x => !x.IsValid))
268	        {
269	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.InvalidMapPropertyAttributeUsage, invalidMemberConfig.Location);
270	        }
271	
272	        return new MembersMappingConfiguration(
273	            ignoredSourceMembers,
274	            ignoredTargetMembers,
275	            memberValueConfigurations,
276	            memberConfigurations,
277	            nestedMembersConfigurations,
278	            ignoreObsolete,
279	            requiredMapping
280	        );
281	    }
282	
283	    private EnumMappingConfiguration BuildEnumConfig(MappingConfigurationReference configRef)
284	    {
285	        if (configRef.Method == null)
286	            return MapperConfiguration.Enum;
287	
288	        var configData = _dataAccessor.AccessFirstOrDefault<MapEnumAttribute, EnumConfiguration>(configRef.Method);
289	        var explicitMappings = _dataAccessor.Access<MapEnumValueAttribute, EnumValueMappingConfiguration>(configRef.Method).ToList();
290	        var ignoredSources = _dataAccessor
291	            .Access<MapperIgnoreSourceValueAttribute, MapperIgnoreEnumValueConfiguration>(configRef.Method)
292	            .Select(x => x.Value)
293	            .ToList();
294	        var ignoredTargets = _dataAccessor
295	            .Access<MapperIgnoreTargetValueAttribute, MapperIgnoreEnumValueConfiguration>(configRef.Method)
296	            .Select(x => x.Value)
297	            .ToList();
298	        var requiredMapping = _dataAccessor.AccessFirstOrDefault<MapperRequiredMappingAttribute>(configRef.Method)?.RequiredMappingStrategy;
299	
300	        // ignore the required mapping as the same attribute is used for other mapping types
301	        // e.g. object to object
302	        var hasEnumConfigs = configData != null || explicitMappings.Count > 0 || ignoredSources.Count > 0 || ignoredTargets.Count > 0;
303	        if (hasEnumConfigs && !configRef.Source.IsEnum() && !configRef.Target.IsEnum())
304	        {
305	            _diagnostics.ReportDiagnostic(DiagnosticDescriptors.EnumConfigurationOnNonEnumMapping, configRef.Method);
306	            return MapperConfiguration.Enum;
307	        }
308	
309	        return new EnumMappingConfiguration(
310	            configData?.Strategy ?? MapperConfiguration.Enum.Strategy,
311	            configData?.IgnoreCase ?? MapperConfiguration.Enum.IgnoreCase,
312	            configData?.FallbackValue,
313	            ignoredSources,
314	            ignoredTargets,
315	            explicitMappings,
316	            requiredMapping ?? MapperConfiguration.Enum.RequiredMappingStrategy,
317	            configData?.NamingStrategy ?? MapperConfiguration.Enum.NamingStrategy
318	        );
319	    }
320	}
