15	public class SymbolAccessor(CompilationContext compilationContext, INamedTypeSymbol mapperSymbol)
16	{
17	    private const string GlobalPrefix = "global::";
18	
19	    // this is a weak reference table
20	    // since if there is no reference to the key
21	    // the values should not be kept in the memory anymore / are not needed anymore.
22	    private readonly ConditionalWeakTable<ITypeSymbol, ITypeSymbol> _originalNullableTypes = new();
23	    private readonly Dictionary<ISymbol, ImmutableArray<AttributeData>> _attributes = new(SymbolEqualityComparer.Default);
24	    private readonly Dictionary<ITypeSymbol, IReadOnlyCollection<ISymbol>> _allMembers = new(SymbolEqualityComparer.Default);
25	    private readonly Dictionary<ITypeSymbol, IReadOnlyCollection<IMappableMember>> _allAccessibleMembers = new(
26	        SymbolEqualityComparer.Default
27	    );
28	    private readonly Dictionary<ITypeSymbol, IReadOnlyDictionary<string, IMappableMember>> _allAccessibleMembersCaseInsensitive = new(
29	        SymbolEqualityComparer.Default
30	    );
31	    private readonly Dictionary<ITypeSymbol, IReadOnlyDictionary<string, IMappableMember>> _allAccessibleMembersCaseSensitive = new(
32	        SymbolEqualityComparer.Default
33	    );
34	
35	    private MemberVisibility _memberVisibility = MemberVisibility.AllAccessible;
36	    private MemberVisibility _constructorVisibility = MemberVisibility.AllAccessible;
37	
38	    private Compilation Compilation => compilationContext.Compilation;
39	
40	    private readonly Lazy<INamedTypeSymbol> _lazyEnumerableType = new(() =>
41	        compilationContext.Compilation.GetSpecialType(SpecialType.System_Collections_Generic_IEnumerable_T)
42	    );
