49	    public bool HasDirectlyAccessibleParameterlessConstructor(ITypeSymbol symbol) =>
50	        symbol is INamedTypeSymbol { IsAbstract: false } namedTypeSymbol
51	        && namedTypeSymbol.InstanceConstructors.Any(c => c.Parameters.IsDefaultOrEmpty && IsDirectlyAccessible(c));
