61	    public bool IsDirectlyAccessible(ISymbol symbol) => Compilation.IsSymbolAccessibleWithin(symbol, mapperSymbol);
62	
63	    public bool IsMemberAccessible(ISymbol symbol)
64	    {
65	        Debug.Assert(symbol is not IMethodSymbol { MethodKind: MethodKind.Constructor });
66	        return IsAccessible(symbol, _memberVisibility);
67	    }
68	
69	    public bool IsConstructorAccessible(IMethodSymbol symbol)
70	    {
71	        Debug.Assert(symbol.MethodKind == MethodKind.Constructor);
72	        return IsAccessible(symbol, _constructorVisibility);
73	    }
