75	    private bool IsAccessible(ISymbol symbol, MemberVisibility visibility)
76	    {
77	        if (visibility.HasFlag(MemberVisibility.Accessible) && !IsDirectlyAccessible(symbol))
78	            return false;
79	
80	        return symbol.DeclaredAccessibility switch
81	        {
82	            Accessibility.Private => visibility.HasFlag(MemberVisibility.Private),
83	            Accessibility.ProtectedAndInternal => visibility.HasFlag(MemberVisibility.Protected)
84	                && visibility.HasFlag(MemberVisibility.Internal),
85	            Accessibility.Protected => visibility.HasFlag(MemberVisibility.Protected),
86	            Accessibility.Internal => visibility.HasFlag(MemberVisibility.Internal),
87	            Accessibility.ProtectedOrInternal => visibility.HasFlag(MemberVisibility.Protected)
88	                || visibility.HasFlag(MemberVisibility.Internal),
89	            Accessibility.Public => visibility.HasFlag(MemberVisibility.Public),
90	            _ => false,
91	        };
92	    }
93	
94	    public bool IsNullable(ISymbol symbol)
95	    {
96	        return symbol switch
97	        {
98	            ITypeSymbol t => t.IsNullable(),
99	            IPropertySymbol p => p.Type.IsNullable() || TryHasAttribute<MaybeNullAttribute>(p),
100	            IFieldSymbol f => f.Type.IsNullable() || TryHasAttribute<MaybeNullAttribute>(f),
101	            IParameterSymbol p => p.Type.IsNullable() || TryHasAttribute<MaybeNullAttribute>(p),
102	            _ => false,
103	        };
104	    }
105	
106	    public bool MayReturnNull(IMethodSymbol symbol, bool treatUnannotatedAsNullable = true)
107	    {
108	        // only treat annotated as nullable
109	        return symbol.ReturnNullableAnnotation.IsNullable(treatUnannotatedAsNullable)
110	            || symbol.ReturnType.IsNullableValueType()
111	            || symbol.ReturnType.NullableAnnotation.IsNullable(treatUnannotatedAsNullable)
112	            || TryHasAttribute<MaybeNullAttribute>(symbol.GetReturnTypeAttributes());
113	    }
114	
115	    public bool HasImplicitConversion(ITypeSymbol source, ITypeSymbol destination) =>
116	        Compilation.ClassifyConversion(source, destination).IsImplicit && (destination.IsNullable() || !source.IsNullable());
117	
118	    /// <summary>
119	    /// Returns true when a conversion form the <paramref name="sourceType"/>
120	    /// to the <paramref name="targetType"/> is possible with a conversion
121	    /// of type identity, boxing or implicit and compatible nullability.
122	    /// </summary>
123	    /// <param name="sourceType">The source type.</param>
124	    /// <param name="targetType">The target type.</param>
125	    /// <returns>Whether the assignment is valid</returns>
126	    public bool CanAssign(ITypeSymbol sourceType, ITypeSymbol targetType)
127	    {
128	        var conversion = Compilation.ClassifyConversion(sourceType, targetType);
129	        return (conversion.IsIdentity || conversion.IsBoxing || conversion.IsImplicit)
130	            && (targetType.IsNullable() || !sourceType.IsNullable());
131	    }
