133	    public MethodParameter? WrapOptionalMethodParameter(IParameterSymbol? symbol) => symbol == null ? null : WrapMethodParameter(symbol);
134	
135	    public MethodParameter WrapMethodParameter(IParameterSymbol symbol) => new(symbol, UpgradeNullable(symbol.Type));
136	
137	    /// <summary>
138	    /// Upgrade the nullability of a symbol from <see cref="NullableAnnotation.None"/> to <see cref="NullableAnnotation.Annotated"/>.
139	    /// Value types are not upgraded.
140	    /// </summary>
141	    /// <param name="symbol">The symbol to upgrade.</param>
142	    /// <returns>The upgraded symbol</returns>
143	    internal ITypeSymbol UpgradeNullable(ITypeSymbol symbol)
144	    {
145	        TryUpgradeNullable(symbol, out var upgradedSymbol);
146	        return upgradedSymbol ?? symbol;
147	    }
148	
149	    /// <summary>
150	    /// Tries to upgrade the nullability of a symbol from <see cref="NullableAnnotation.None"/> to <see cref="NullableAnnotation.Annotated"/>.
151	    /// Value types are not upgraded.
152	    /// </summary>
153	    /// <param name="symbol">The symbol.</param>
154	    /// <param name="upgradedSymbol">The upgraded symbol, if an upgrade has taken place, <c>null</c> otherwise.</param>
155	    /// <returns>Whether an upgrade has taken place.</returns>
156	    internal bool TryUpgradeNullable(ITypeSymbol symbol, [NotNullWhen(true)] out ITypeSymbol? upgradedSymbol)
157	    {
158	        if (symbol.NullableAnnotation != NullableAnnotation.None || symbol.IsValueType)
159	        {
160	            upgradedSymbol = default;
161	            return false;
162	        }
163	
164	        upgradedSymbol = UpgradeInnerSymbols(symbol).WithNullableAnnotation(NullableAnnotation.Annotated);
165	
166	        _originalNullableTypes.Add(upgradedSymbol, symbol);
167	        return true;
168	    }
169	
170	    private ITypeSymbol UpgradeInnerSymbols(ITypeSymbol symbol)
171	    {
172	        TryUpgradeInnerSymbols(symbol, out var upgradedSymbol);
173	        return upgradedSymbol ?? symbol;
174	    }
175	
176	    /// <summary>
177	    /// Tries to upgrade the nullability of generic type arguments and array element type from <see cref="NullableAnnotation.None"/> to <see cref="NullableAnnotation.Annotated"/>.
178	    /// If generic type parameter is notnull, it will be upgraded to <see cref="NullableAnnotation.NotAnnotated"/>
179	    /// </summary>
180	    /// <param name="symbol">The symbol.</param>
181	    /// <param name="upgradedSymbol">The symbol with upgraded inner symbols.</param>
182	    /// <returns>Whether an upgrade has taken place.</returns>
183	    private bool TryUpgradeInnerSymbols(ITypeSymbol symbol, [NotNullWhen(true)] out ITypeSymbol? upgradedSymbol)
184	    {
185	        switch (symbol)
186	        {
187	            case INamedTypeSymbol { TypeArguments.Length: > 0 } namedSymbol:
188	                var upgradedTypeArguments = UpgradeGenericTypeArguments(namedSymbol.TypeParameters, namedSymbol.TypeArguments);
189	                upgradedSymbol = namedSymbol.ConstructedFrom.Construct(
190	                    upgradedTypeArguments,
191	                    upgradedTypeArguments.Select(ta => ta.NullableAnnotation).ToImmutableArray()
192	                );
193	                return true;
194	
195	            case IArrayTypeSymbol { ElementType.IsValueType: false, ElementNullableAnnotation: NullableAnnotation.None } arrayTypeSymbol:
196	                upgradedSymbol = Compilation.CreateArrayTypeSymbol(
197	                    UpgradeNullable(arrayTypeSymbol.ElementType),
198	                    arrayTypeSymbol.Rank,
199	                    NullableAnnotation.Annotated
200	                );
201	                return true;
202	
203	            default:
204	                upgradedSymbol = default;
205	                return false;
206	        }
207	    }
208	
209	    /// <summary>
210	    /// Upgrades the nullability of generic type arguments.
211	    /// If notnull constraint is applied to the parameter, symbol will be upgraded to <see cref="NullableAnnotation.NotAnnotated"/>,
212	    /// otherwise to <see cref="NullableAnnotation.Annotated"/>.
213	    /// </summary>
214	    /// <param name="typeParameters">The type parameters of the generic type.</param>
215	    /// <param name="typeArguments">The type arguments of the generic type.</param>
216	    /// <returns>Upgraded generic type arguments.</returns>
217	    private ImmutableArray<ITypeSymbol> UpgradeGenericTypeArguments(
218	        ImmutableArray<ITypeParameterSymbol> typeParameters,
219	        ImmutableArray<ITypeSymbol> typeArguments
220	    )
221	    {
222	        Debug.Assert(typeArguments.Length == typeParameters.Length);
223	        Debug.Assert(typeArguments.Length > 0);
224	
225	        var arguments = new ITypeSymbol[typeArguments.Length];
226	        for (var i = 0; i < typeArguments.Length; i++)
227	        {
228	            var typeParameter = typeParameters[i];
229	            var typeArgument = typeArguments[i];
230	
231	            var upgradedSymbol = typeParameter switch
232	            {
233	                { HasNotNullConstraint: true } => UpgradeInnerSymbols(typeArgument).WithNullableAnnotation(NullableAnnotation.NotAnnotated),
234	                _ => UpgradeNullable(typeArgument),
235	            };
236	
237	            arguments[i] = upgradedSymbol;
238	        }
239	
240	        return arguments.ToImmutableArray();
241	    }
242	
243	    /// <summary>
244	    /// Returns a non-nullable variant of <paramref name="type"/>
245	    /// if the <paramref name="userMappingType"/> declared by the user
246	    /// does not have nullable annotations (<see cref="NullableAnnotation.None"/>).
247	    /// If no user-mapping type is provided, the <paramref name="type"/> is used
248	    /// to resolve the original nullable values.
249	    /// This can be used in contexts where the original nullable annotations are important
250	    /// (the not-yet "upgraded" values).
251	    /// Usually this is the case if <see cref="NullableAnnotation.None"/> should
252	    /// behave differently than <see cref="NullableAnnotation.Annotated"/>
253	    /// (<see cref="NullableAnnotation.None"/> is upgraded to <see cref="NullableAnnotation.Annotated"/>
254	    /// while reading the user symbols).
255	    /// </summary>
256	    /// <param name="type">The type</param>
257	    /// <param name="userMappingType">The user mapping type.</param>
258	    /// <returns>The <paramref name="type"/> or its non-nullable variant.</returns>
259	    internal ITypeSymbol NonNullableIfNullableReferenceTypesDisabled(ITypeSymbol type, ITypeSymbol? userMappingType = null)
260	    {
261	        if (
262	            type.IsNullableReferenceType()
263	            && _originalNullableTypes.TryGetValue(userMappingType ?? type, out var originalType)
264	            && originalType.NullableAnnotation == NullableAnnotation.None
265	        )
266	        {
267	            return type.NonNullable();
268	        }
269	
270	        return type;
271	    }
