290	    internal IEnumerable<AttributeData> GetAttributes(ITypeSymbol attributeSymbol, IEnumerable<AttributeData> attributes)
291	    {
292	        foreach (var attr in attributes)
293	        {
294	            if (SymbolEqualityComparer.Default.Equals(attr.AttributeClass?.ConstructedFrom ?? attr.AttributeClass, attributeSymbol))
295	            {
296	                yield return attr;
297	            }
298	        }
