368	    internal bool TryFindMemberPath(
369	        IReadOnlyDictionary<string, IMappableMember> members,
370	        IEnumerable<StringMemberPath> pathCandidates,
371	        bool ignoreCase,
372	        [NotNullWhen(true)] out MemberPath? memberPath
373	    )
374	    {
375	        var foundPath = new List<IMappableMember>();
376	        foreach (var pathCandidate in pathCandidates)
377	        {
378	            if (!members.TryGetValue(pathCandidate.Path[0], out var member))
379	                continue;
380	
381	            foundPath.Clear();
382	            foundPath.Add(member);
383	            if (pathCandidate.Path.Count != 1 && !TryFindPath(member.Type, pathCandidate.SkipRoot(), ignoreCase, foundPath))
384	                continue;
385	
386	            memberPath = new NonEmptyMemberPath(member.Type, foundPath);
387	            return true;
388	        }
389	
390	        memberPath = null;
391	        return false;
392	    }
393	
394	    internal bool TryFindMemberPath(
395	        ITypeSymbol type,
396	        IEnumerable<StringMemberPath> pathCandidates,
397	        IReadOnlyCollection<string> ignoredNames,
398	        bool ignoreCase,
399	        [NotNullWhen(true)] out MemberPath? memberPath
400	    )
401	    {
402	        var foundPath = new List<IMappableMember>();
403	        foreach (var pathCandidate in pathCandidates)
404	        {
405	            // fast path for exact case matches
406	            if (ignoredNames.Contains(pathCandidate.Path[0]))
407	                continue;
408	
409	            // reuse List instead of allocating a new one
410	            foundPath.Clear();
411	            if (!TryFindPath(type, pathCandidate, ignoreCase, foundPath))
412	                continue;
413	
414	            // match again to respect ignoreCase parameter
415	            if (ignoredNames.Contains(foundPath[0].Name))
416	                continue;
417	
418	            memberPath = new NonEmptyMemberPath(type, foundPath);
419	            return true;
420	        }
421	
422	        memberPath = null;
423	        return false;
424	    }
425	
426	    internal bool TryFindMemberPath(ITypeSymbol type, IMemberPathConfiguration path, [NotNullWhen(true)] out MemberPath? memberPath)
427	    {
428	        if (path is StringMemberPath stringMemberPath)
429	            return TryFindMemberPath(type, stringMemberPath, out memberPath);
430	
431	        // resolve from symbol member path
432	        // if it is not possible to resolve by direct symbols
433	        // the string path is tried to ensure backwards compatibility
434	        // (e.g. when the A.MyValue is referenced,
435	        // but instead B.MyValue is the correct one,
436	        // with the string representation it doesn't matter, it is just MyValue).
437	        var symbolMemberPath = (SymbolMemberPath)path;
438	        var memberPathSegments = new List<IMappableMember>(symbolMemberPath.PathCount);
439	        foreach (var pathSegment in symbolMemberPath.Path)
440	        {
441	            if (MappableMember.Create(this, pathSegment) is { } mappableMember)
442	            {
443	                memberPathSegments.Add(mappableMember);
444	                continue;
445	            }
446	
447	            return TryFindMemberPath(type, symbolMemberPath.ToStringMemberPath(), out memberPath);
448	        }
449	
450	        var nameOfRefType = memberPathSegments[0].ContainingType;
451	        if (nameOfRefType == null || !CanAssign(type, nameOfRefType))
452	        {
453	            return TryFindMemberPath(type, symbolMemberPath.ToStringMemberPath(), out memberPath);
454	        }
455	
456	        memberPath = new NonEmptyMemberPath(type, memberPathSegments);
457	        return true;
458	    }
459	
460	    internal bool TryFindMemberPath(ITypeSymbol type, StringMemberPath path, [NotNullWhen(true)] out MemberPath? memberPath)
461	    {
462	        var foundPath = new List<IMappableMember>();
463	        if (TryFindPath(type, path, false, foundPath))
464	        {
465	            memberPath = MemberPath.Create(type, foundPath);
466	            return true;
467	        }
468	
469	        memberPath = null;
470	        return false;
471	    }
472	
473	    /// <summary>
474	    ///     Checks that the specified method returns a type that can be assigned to the specified result type,
475	    ///     and that the specified arguments can be passed to the method.
476	    ///     The check takes into account the possibility of assignment to a method with an argument marked with the <see langword="params"/> keyword
477	    /// </summary>
478	    /// <param name="method">Method for validate</param>
479	    /// <param name="returnType">Target return type</param>
480	    /// <param name="argTypes">Target method arguments</param>
481	    /// <returns></returns>
482	    internal bool ValidateSignature(IMethodSymbol method, ITypeSymbol returnType, params ITypeSymbol[] argTypes)
483	    {
484	        return CanAssign(method.ReturnType, returnType) && Enumerable.Range(0, method.Parameters.Length).All(IsValidParameter);
485	
486	        bool IsValidParameter(int i)
487	        {
488	            if (method.Parameters[i] is not { IsParams: true } isParamsParameter)
489	            {
490	                return CanAssign(argTypes[i], method.Parameters[i].Type);
491	            }
492	
493	            // see https://learn.microsoft.com/en-us/dotnet/csharp/language-reference/keywords/method-parameters#params-modifier
494	
495	            var argsToEnd = argTypes.AsSpan(i);
496	
497	            // for empty args aka Call(params X[]) as Call()
498	            if (argsToEnd.IsEmpty)
499	            {
500	                return true;
501	            }
502	
503	            var elementType = isParamsParameter.Type.ImplementsGeneric(EnumerableTypeSymbol, out var impl)
504	                // for assignable to IEnumerable<T>
505	                ? impl.TypeArguments.First()
506	                // for Span<T> and ReadOnlySpan<T>
507	                : ((INamedTypeSymbol)method.Parameters[i].Type).TypeArguments.First();
508	
509	            //for single arg aka Call(X[]) or Call(X)
510	            if (argsToEnd.Length == 1)
511	            {
512	                return CanAssign(argsToEnd[0], method.Parameters[i].Type) || CanAssign(argsToEnd[0], elementType);
513	            }
514	
515	            // for multiple args
516	            foreach (var typeSymbol in argsToEnd)
517	            {
518	                if (!CanAssign(typeSymbol, elementType))
519	                {
520	                    return false;
521	                }
522	            }
523	
524	            return true;
525	        }
526	    }
527	
528	    private bool TryFindPath(ITypeSymbol type, StringMemberPath path, bool ignoreCase, ICollection<IMappableMember> foundPath)
529	    {
530	        foreach (var name in path.Path)
531	        {
532	            // get T if type is Nullable<T>, prevents Value being treated as a member
533	            var actualType = type.NonNullableValueType() ?? type;
534	            if (GetMappableMember(actualType, name, ignoreCase) is not { } member)
535	                return false;
536	
537	            type = member.Type;
538	            foundPath.Add(member);
539	        }
540	
541	        return true;
542	    }
543	
544	    public IMappableMember? GetMappableMember(ITypeSymbol symbol, string name, bool ignoreCase = false)
545	    {
546	        var membersBySymbol = ignoreCase ? _allAccessibleMembersCaseInsensitive : _allAccessibleMembersCaseSensitive;
547	
548	        if (membersBySymbol.TryGetValue(symbol, out var symbolMembers))
549	            return symbolMembers.GetValueOrDefault(name);
550	
551	        var comparer = ignoreCase ? StringComparer.OrdinalIgnoreCase : StringComparer.Ordinal;
552	        membersBySymbol[symbol] = symbolMembers = GetAllAccessibleMappableMembers(symbol)
553	            .GroupBy(x => x.Name, comparer)
554	            .ToDictionary(x => x.Key, x => x.First(), comparer);
555	        return symbolMembers.GetValueOrDefault(name);
556	    }
557	
558	    public TOperation? GetOperation<TOperation>(SyntaxNode node)
559	        where TOperation : class, IOperation => compilationContext.GetSemanticModel(node.SyntaxTree)?.GetOperation(node) as TOperation;
560	
561	    public INamedTypeSymbol? GetTypeByMetadataName(string targetTypeName)
562	    {
563	        var startsWithGlobal = targetTypeName.StartsWith(GlobalPrefix, StringComparison.Ordinal);
564	        if (startsWithGlobal)
565	        {
566	            targetTypeName = targetTypeName[GlobalPrefix.Length..];
567	        }
568	
569	        return Compilation.GetBestTypeByMetadataName(targetTypeName);
570	    }
571	
572	    private ImmutableArray<AttributeData> GetAttributesCore(ISymbol symbol)
573	    {
574	        if (_attributes.TryGetValue(symbol, out var attributes))
575	        {
576	            return attributes;
577	        }
578	
579	        attributes = symbol.GetAttributes();
580	        _attributes.Add(symbol, attributes);
581	
582	        return attributes;
583	    }
584	
585	    private IEnumerable<ISymbol> GetAllMembersCore(ITypeSymbol symbol)
586	    {
587	        var members = symbol.GetMembers();
588	
589	        if (symbol.TypeKind == TypeKind.Interface)
590	        {
591	            var interfaceProperties = symbol.AllInterfaces.SelectMany(GetAllMembers);
592	            return members.Concat(interfaceProperties);
593	        }
594	
595	        return symbol.BaseType == null ? members : members.Concat(GetAllMembers(symbol.BaseType));
596	    }
597	
598	    private IEnumerable<IMappableMember> GetAllAccessibleMappableMembersCore(ITypeSymbol symbol)
599	    {
600	        if (symbol.IsTupleType && symbol is INamedTypeSymbol namedType)
601	        {
602	            return namedType.TupleElements.Select(x => MappableMember.Create(this, x)).WhereNotNull();
603	        }
604	
605	        // member must be property or a none backing variable field
606	        return GetAllMembers(symbol)
607	            .Where(x => x is { IsStatic: false, Kind: SymbolKind.Property } or IFieldSymbol { IsStatic: false, AssociatedSymbol: null })
608	            .DistinctBy(x => x.Name)
609	            .Select(x => MappableMember.Create(this, x))
610	            .WhereNotNull();
611	    }
612	}
