        var ctor = FindSingleArgCtor(namedTarget, ctx.Source, ctx.SymbolAccessor);
        if (ctor == null)
            return null;

        return new CtorMapping(ctx.Source, ctx.Target, ctx.InstanceConstructors.BuildForConstructor(ctor));
